using System;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Get the source file content from the binlog
Console.WriteLine("=== LOOKING FOR SOURCE FILE CONTENT ===");
build.VisitAllChildren<CscCommandLineArgs>(csc =>
{
    var proj = csc.GetNearestParent<Project>();
    Console.WriteLine($"CSC for: {proj?.Name}");
    foreach (var child in csc.Children)
        Console.WriteLine($"  {child}");
    Console.WriteLine();
});

// Check for task inputs/outputs
build.VisitAllChildren<Microsoft.Build.Logging.StructuredLogger.Task>(task =>
{
    if (task.Name == "Csc")
    {
        var proj = task.GetNearestParent<Project>();
        Console.WriteLine($"Csc Task in: {proj?.Name}");
        foreach (var child in task.Children)
        {
            if (child is Folder folder)
            {
                Console.WriteLine($"  Folder: {folder.Name}");
                foreach (var item in folder.Children)
                    Console.WriteLine($"    {item}");
            }
        }
        Console.WriteLine();
    }
});

// Show the project dependency chain for failed builds
Console.WriteLine("=== BUILD DEPENDENCY CHAIN ===");
build.VisitAllChildren<Project>(project =>
{
    bool isActualBuild = false;
    project.VisitAllChildren<Microsoft.Build.Logging.StructuredLogger.Target>(t =>
    {
        if (t.Name == "CoreCompile" || t.Name == "Build")
            isActualBuild = true;
    });
    if (!isActualBuild) return;

    bool hasErrors = false;
    project.VisitAllChildren<Error>(e => hasErrors = true);
    if (hasErrors)
    {
        Console.WriteLine($"FAILED: {project.Name}");
        project.VisitAllChildren<Error>(e =>
        {
            Console.WriteLine($"  Error {e.Code}: {e.Text}");
            Console.WriteLine($"    at {e.File}:{e.LineNumber}");
        });
    }
});
