{
    if (task.Name != "Csc") return;
    var proj = task.GetNearestParent<Project>();
    Console.WriteLine($"\n--- {proj?.Name} ---");
    task.VisitAllChildren<Property>(prop =>
    {
        if (prop.Name == "CommandLineArguments")
            Console.WriteLine(prop.Value);
